import{_ as a,o as t,c as o,al as i}from"./chunks/framework.0kWfx6nb.js";const p=JSON.parse('{"title":"Firmware Updates (DFU)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/dfu.md","filePath":"guide/dfu.md"}'),r={name:"guide/dfu.md"};function n(s,e,l,d,u,c){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="firmware-updates-dfu" tabindex="-1">Firmware Updates (DFU) <a class="header-anchor" href="#firmware-updates-dfu" aria-label="Permalink to &quot;Firmware Updates (DFU)&quot;">​</a></h1><p>Boks devices can be updated wirelessly using the <strong>Device Firmware Update (DFU)</strong> protocol over Bluetooth. This allows the hardware to receive bug fixes and new features.</p><h2 id="safety-protection" tabindex="-1">Safety &amp; Protection <a class="header-anchor" href="#safety-protection" aria-label="Permalink to &quot;Safety &amp; Protection&quot;">​</a></h2><p>The Boks update system is designed to be <strong>protected</strong>. The hardware uses signed firmware packages; if a user attempts to send a fake or invalid update packet, the Boks will refuse to install it.</p><h2 id="⚠️-critical-warning-for-boks-v3-non-nfc-nrf52811" tabindex="-1">⚠️ Critical Warning for Boks V3 (Non-NFC / nRF52811) <a class="header-anchor" href="#⚠️-critical-warning-for-boks-v3-non-nfc-nrf52811" aria-label="Permalink to &quot;⚠️ Critical Warning for Boks V3 (Non-NFC / nRF52811)&quot;">​</a></h2><p>If you own a <strong>Non-NFC Boks</strong> (also known as Boks V3, running on the nRF52811 chip), please read this carefully:</p><ul><li><strong>An invalid or interrupted update will delete the previous software.</strong></li><li>In this case, the Boks will remain stuck in &quot;DFU Mode&quot; (bootloader) waiting for a valid software update and <strong>will never restart</strong> on the old version.</li><li>You must provide a valid firmware file to restore functionality.</li></ul><p>This behavior is different from the <strong>NFC Boks</strong> (V4 / nRF52833), which can safely roll back or restart on its previous software if an update fails.</p><h2 id="how-to-update" tabindex="-1">How to Update <a class="header-anchor" href="#how-to-update" aria-label="Permalink to &quot;How to Update&quot;">​</a></h2><h3 id="using-the-sdk" tabindex="-1">Using the SDK <a class="header-anchor" href="#using-the-sdk" aria-label="Permalink to &quot;Using the SDK&quot;">​</a></h3><p>The Boks SDK itself does not yet include a built-in DFU client. However, you can use the firmware files retrieved via the SDK with standard tools.</p><h3 id="manual-update-fallback" tabindex="-1">Manual Update (Fallback) <a class="header-anchor" href="#manual-update-fallback" aria-label="Permalink to &quot;Manual Update (Fallback)&quot;">​</a></h3><p>If you have the firmware <code>.zip</code> package:</p><ol><li>Install the <strong>nRF Connect for Mobile</strong> app (available on Android and iOS).</li><li>Put your Boks in DFU mode (this happens automatically when a DFU process is initiated, or after a failed update).</li><li>Connect to the device (usually named <code>DfuTarg</code> or <code>Boks_DFU</code>).</li><li>Upload the firmware <code>.zip</code> file using the DFU button in the app.</li></ol>',14)])])}const f=a(r,[["render",n]]);export{p as __pageData,f as default};
